(function () {
  function isDesktop() {
    return window.matchMedia("(min-width: 1024px)").matches;
  }

  function setActiveSlide(slides, activeSlide) {
    slides.forEach((slide) => {
      const active = slide === activeSlide;
      slide.style.display = active ? "" : "none";
      slide.classList.toggle("is-active", active);
      slide.setAttribute("aria-hidden", active ? "false" : "true");
    });
  }

  function bindThumbs(container) {
    const splideRoot = container.querySelector(".splide");
    if (!splideRoot) return;

    const slides = Array.from(splideRoot.querySelectorAll(".splide__slide"));
    if (!slides.length) return;

    const thumbs = Array.from(container.querySelectorAll(".product-thumb[data-thumb-media-id]"));
    if (!thumbs.length) return;

    if (container.dataset.thumbsBound === "1") return;
    container.dataset.thumbsBound = "1";

    // helper: vind slide op basis van media-id
    const findSlideByMediaId = (mediaId) => {
      return slides.find((slide) => slide.querySelector(`[data-media-id="${mediaId}"]`));
    };

    // init: eerste zichtbare slide = eerste in DOM
    setActiveSlide(slides, slides[0]);
    thumbs[0]?.classList.add("is-active");

    thumbs.forEach((btn) => {
      btn.addEventListener("click", (e) => {
        e.preventDefault();

        const mediaId = btn.getAttribute("data-thumb-media-id");
        if (!mediaId) return;

        const targetSlide = findSlideByMediaId(mediaId);
        if (!targetSlide) return;

        setActiveSlide(slides, targetSlide);

        thumbs.forEach((t) => t.classList.remove("is-active"));
        btn.classList.add("is-active");
      });
    });
  }

  function syncProductColumnHeight() {
    const wrapper = document.querySelector(".product-media-content-wrapper");
    if (!wrapper) return;
    const media = wrapper.querySelector(".product-media-container");
    const content = wrapper.querySelector(".product-content-container");
    if (!media || !content) return;

    function update() {
      requestAnimationFrame(function () {
        if (isDesktop()) {
          const h = media.offsetHeight;
          if (h > 0) content.style.maxHeight = h + "px";
        } else {
          content.style.maxHeight = "";
        }
      });
    }

    update();
    new ResizeObserver(update).observe(media);
    window.addEventListener("load", update);
    window.addEventListener("resize", update);
  }

  function run() {
    if (!isDesktop()) return;
    document.querySelectorAll(".product-media-container").forEach(bindThumbs);
  }

  document.addEventListener("DOMContentLoaded", function () {
    run();
    syncProductColumnHeight();
  });
  window.addEventListener("resize", run);
})();
